def HSS(points, k: int, reference_point) -> np.ndarray:
    n, m = points.shape

    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    # 创建索引列表
    R_indices = list(range(n))
    R_objectives_array = points
    random.shuffle(R_indices)

    # 1. GSI算法 - 初始化
    S = set(R_indices[:k])
    elements_to_insert = R_indices[k:]

    # 2. GSI算法 - 迭代过程
    for element_to_add in elements_to_insert:
        S.add(element_to_add)

        worst_element_index = None
        min_contribution = float('inf')

        # 获取当前 S 的超体积
        if not S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        for s_index in list(S):
            # 尝试移除 s_index: S_temp = S - {s_index}
            S_temp = S - {s_index}

            # 移除后的超体积
            if not S_temp:
                M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                temp_selected = np.empty((0, M))
            else:
                temp_selected = R_objectives_array[list(S_temp)]

            if temp_selected.size == 0:
                hv_after_remove = 0.0
            else:
                try:
                    hv = pg.hypervolume(temp_selected)
                    hv_after_remove = hv.compute(reference_point)
                except Exception as e:
                    print(f"Hypervolume calculation error: {e}")
                    hv_after_remove = 0.0

            # 贡献度 = 移除前的 HV - 移除后的 HV
            contribution = current_hv - hv_after_remove

            if contribution < min_contribution:
                min_contribution = contribution
                worst_element_index = s_index

        if worst_element_index is not None:
            S.remove(worst_element_index)

    # 3. LS算法 - 初始化
    current_S = set(S)
    R_set = set(R_indices)

    if len(current_S) != k:
        raise ValueError("初始子集 S 的大小必须等于 k。")

    # 4. LS算法 - 迭代过程
    while True:
        # 获取当前 S 的超体积
        if not current_S:
            M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
            current_selected = np.empty((0, M))
        else:
            current_selected = R_objectives_array[list(current_S)]

        if current_selected.size == 0:
            current_hv = 0.0
        else:
            try:
                hv = pg.hypervolume(current_selected)
                current_hv = hv.compute(reference_point)
            except Exception as e:
                print(f"Hypervolume calculation error: {e}")
                current_hv = 0.0

        found_improvement = False

        R_minus_S = list(R_set - current_S)
        S_list = list(current_S)

        # 遍历所有可能的交换对 (s, r)
        for s_index in S_list:
            for r_index in R_minus_S:
                # 尝试交换: S' = S - {s_index} + {r_index}
                S_new = (current_S - {s_index}) | {r_index}

                # 计算新集合 S_new 的超体积
                if not S_new:
                    M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
                    new_selected = np.empty((0, M))
                else:
                    new_selected = R_objectives_array[list(S_new)]

                if new_selected.size == 0:
                    new_hv = 0.0
                else:
                    try:
                        hv = pg.hypervolume(new_selected)
                        new_hv = hv.compute(reference_point)
                    except Exception as e:
                        print(f"Hypervolume calculation error: {e}")
                        new_hv = 0.0

                # 检查是否是改进
                if new_hv > current_hv:
                    current_S = S_new
                    found_improvement = True
                    break  # 跳出 r_index 循环

            if found_improvement:
                break  # 跳出 s_index 循环

        if not found_improvement:
            break

    # 5. 返回选择的点
    if not current_S:
        M = R_objectives_array.shape[1] if R_objectives_array.ndim == 2 else 0
        selected_points = np.empty((0, M))
    else:
        selected_points = R_objectives_array[list(current_S)]

    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    """
    HSS (Hypervolume-based Subset Selection): 贪心选择超体积贡献最大的 k 个点

    参数:
        points: np.ndarray
            所有候选点，形状为 (N, D)，其中 N 是点数，D 是目标维度
        k: int
            需要选择的点数
        reference_point: np.ndarray, optional
            参考点，形状为 (D,)。如果为 None，则使用 points 的最大值 * 1.1

    返回:
        subset: np.ndarray
            选出的子集，形状为 (k, D)
    """
    import numpy as np
    import random
    import pygmo as pg

    n, d = points.shape
    if k <= 0 or k > n:
        raise ValueError("k must be greater than 0 and not larger than the number of points.")

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    hv_cache = {}

    def compute_hv(indices):
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv = 0.0
        else:
            hv = pg.hypervolume(points[list(indices)]).compute(reference_point)
        hv_cache[key] = hv
        return hv

    def greedy_initialization():
        selected = set()
        remaining = set(range(n))

        best_hv = -float('inf')
        best_idx = -1
        for idx in remaining:
            hv = compute_hv([idx])
            if hv > best_hv:
                best_hv = hv
                best_idx = idx

        selected.add(best_idx)
        remaining.remove(best_idx)

        while len(selected) < k:
            best_contrib = -float('inf')
            best_idx = -1
            current_hv = compute_hv(selected)

            eval_points = list(remaining)
            if len(eval_points) > 100:
                eval_points = random.sample(eval_points, 100)

            for idx in eval_points:
                new_set = selected | {idx}
                new_hv = compute_hv(new_set)
                contrib = new_hv - current_hv
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx

            if best_idx != -1:
                selected.add(best_idx)
                remaining.remove(best_idx)
            else:
                if remaining:
                    selected.add(random.choice(list(remaining)))
                    remaining.remove(list(selected)[-1])

        return selected

    population_size = 8
    population = []
    population.append(greedy_initialization())

    for _ in range(population_size - 1):
        base = set(random.sample(list(population[0]), min(k, len(population[0]))))
        while len(base) < k:
            available = set(range(n)) - base
            if available:
                base.add(random.choice(list(available)))
        while len(base) > k:
            base.remove(random.choice(list(base)))
        population.append(base)

    def adaptive_mutation(indices):
        current_size = len(indices)
        new_indices = set(indices)

        if current_size < k:
            add_prob = 0.8
            remove_prob = 0.2
        elif current_size > k:
            add_prob = 0.2
            remove_prob = 0.8
        else:
            add_prob = 0.5
            remove_prob = 0.5

        if random.random() < add_prob and len(new_indices) < n:
            available = set(range(n)) - new_indices
            if available:
                current_hv = compute_hv(new_indices)
                best_contrib = -float('inf')
                best_idx = -1
                eval_avail = list(available)
                if len(eval_avail) > 50:
                    eval_avail = random.sample(eval_avail, 50)
                for idx in eval_avail:
                    temp_set = new_indices | {idx}
                    new_hv = compute_hv(temp_set)
                    contrib = new_hv - current_hv
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = idx
                if best_idx != -1:
                    new_indices.add(best_idx)

        if random.random() < remove_prob and len(new_indices) > 1:
            current_hv = compute_hv(new_indices)
            worst_contrib = float('inf')
            worst_idx = -1
            for idx in new_indices:
                temp_set = new_indices - {idx}
                new_hv = compute_hv(temp_set)
                contrib = current_hv - new_hv
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx
            if worst_idx != -1:
                new_indices.remove(worst_idx)

        while len(new_indices) != k:
            if len(new_indices) < k:
                available = set(range(n)) - new_indices
                if available:
                    new_indices.add(random.choice(list(available)))
            else:
                new_indices.remove(random.choice(list(new_indices)))

        return new_indices

    max_iterations = 100
    no_improvement_limit = 20
    best_solution = None
    best_hv = -float('inf')
    no_improvement = 0

    for iteration in range(max_iterations):
        new_population = []
        for _ in range(population_size):
            candidates = random.sample(population, 3)
            candidate_hvs = [compute_hv(s) for s in candidates]
            parent = candidates[np.argmax(candidate_hvs)]
            offspring = adaptive_mutation(parent)
            new_population.append(offspring)

        combined = population + new_population
        combined_hvs = [compute_hv(s) for s in combined]
        sorted_indices = np.argsort(combined_hvs)[-population_size:]
        population = [combined[i] for i in sorted_indices]

        current_best_hv = max(combined_hvs)
        if current_best_hv > best_hv + 1e-10:
            best_hv = current_best_hv
            best_solution = combined[np.argmax(combined_hvs)]
            no_improvement = 0
        else:
            no_improvement += 1

        if no_improvement >= no_improvement_limit:
            break

    if best_solution is None:
        best_solution = population[0]
        best_hv = compute_hv(best_solution)

    improved = True
    while improved:
        improved = False
        contributions = {}
        for idx in best_solution:
            temp_set = best_solution - {idx}
            hv_without = compute_hv(temp_set)
            contributions[idx] = best_hv - hv_without

        sorted_points = sorted(contributions.items(), key=lambda x: x[1])
        remaining = set(range(n)) - best_solution

        for idx_in, _ in sorted_points[:min(3, k)]:
            best_swap = None
            best_improvement = 0
            eval_remain = list(remaining)
            if len(eval_remain) > 50:
                eval_remain = random.sample(eval_remain, 50)

            for idx_out in eval_remain:
                new_set = (best_solution - {idx_in}) | {idx_out}
                new_hv = compute_hv(new_set)
                improvement = new_hv - best_hv
                if improvement > best_improvement:
                    best_improvement = improvement
                    best_swap = idx_out

            if best_swap is not None and best_improvement > 1e-10:
                best_solution.remove(idx_in)
                best_solution.add(best_swap)
                best_hv = best_hv + best_improvement
                improved = True
                break

    selected_indices = list(best_solution)
    return points[selected_indices]

def HSS(points, k: int, reference_point) -> np.ndarray:
    n, d = points.shape

    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    # Hypervolume computation with caching
    hv_cache = {}
    def compute_hv(indices_set):
        key = frozenset(indices_set)
        if key in hv_cache:
            return hv_cache[key]
        if not indices_set:
            hv = 0.0
        else:
            hv = pg.hypervolume(points[list(indices_set)]).compute(reference_point)
        hv_cache[key] = hv
        return hv

    # 1. Random initialization
    population = []
    for _ in range(10):
        indices = set(random.sample(range(n), k))
        population.append(indices)

    # 2. Evolutionary phase with hypervolume-guided mutation
    def hv_guided_mutation(indices):
        current_hv = compute_hv(indices)
        b = len(indices)
        a = n - b

        # Adaptive mutation probabilities based on size difference
        if b < k:
            add_prob = (k - b + 1) / (2 * a) if a > 0 else 0
            remove_prob = 0
        elif b > k:
            add_prob = 0
            remove_prob = (b - k + 1) / (2 * b) if b > 0 else 0
        else:
            add_prob = 1 / (2 * a) if a > 0 else 0
            remove_prob = 1 / (2 * b) if b > 0 else 0

        new_indices = set(indices)

        # Addition: select point maximizing HV contribution
        if random.random() < add_prob and a > 0:
            unselected = [i for i in range(n) if i not in new_indices]
            best_contrib = -float('inf')
            best_idx = None
            for idx in unselected:
                temp_set = new_indices | {idx}
                new_hv = compute_hv(temp_set)
                contrib = new_hv - current_hv
                if contrib > best_contrib:
                    best_contrib = contrib
                    best_idx = idx
            if best_idx is not None:
                new_indices.add(best_idx)

        # Removal: select point minimizing HV contribution
        if random.random() < remove_prob and b > 0:
            worst_contrib = float('inf')
            worst_idx = None
            for idx in new_indices:
                temp_set = new_indices - {idx}
                new_hv = compute_hv(temp_set)
                contrib = current_hv - new_hv  # Loss when removed
                if contrib < worst_contrib:
                    worst_contrib = contrib
                    worst_idx = idx
            if worst_idx is not None:
                new_indices.remove(worst_idx)

        # Ensure size k by additional random adjustments if needed
        while len(new_indices) != k:
            if len(new_indices) < k:
                unselected = [i for i in range(n) if i not in new_indices]
                if unselected:
                    new_indices.add(random.choice(unselected))
            else:
                new_indices.remove(random.choice(list(new_indices)))

        return new_indices

    # Evolutionary iterations
    iterations = 100
    for _ in range(iterations):
        new_population = []
        for indices in population:
            mutated = hv_guided_mutation(indices)
            new_population.append(mutated)

        # Environmental selection: keep top 10 by HV
        combined = population + new_population
        hv_values = [compute_hv(indices) for indices in combined]
        top_indices = np.argsort(hv_values)[-10:]
        population = [combined[i] for i in top_indices]

    # 3. Exhaustive swap refinement
    best_indices = population[0]
    best_hv = compute_hv(best_indices)

    improved = True
    while improved:
        improved = False
        current_list = list(best_indices)

        # Try all possible swaps
        for i in range(k):
            for j in range(n):
                if j in best_indices:
                    continue

                temp_list = current_list.copy()
                temp_list[i] = j
                temp_set = set(temp_list)
                new_hv = compute_hv(temp_set)

                if new_hv > best_hv + 1e-10:
                    best_indices = temp_set
                    best_hv = new_hv
                    improved = True
                    break
            if improved:
                break

    selected_points = points[list(best_indices)]
    return selected_points

def HSS(points, k: int, reference_point) -> np.ndarray:
    import numpy as np
    import pygmo as pg
    import random

    n, d = points.shape
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    hv_cache = {}

    def compute_hv(indices):
        key = frozenset(indices)
        if key in hv_cache:
            return hv_cache[key]
        if not indices:
            hv_cache[key] = 0.0
        else:
            hv = pg.hypervolume(points[list(indices)])
            hv_cache[key] = hv.compute(reference_point)
        return hv_cache[key]

    # 1. Fast greedy initialization with caching
    selected = set()
    remaining = set(range(n))

    while len(selected) < k:
        best_idx = None
        best_contrib = -np.inf
        current_hv = compute_hv(selected)

        for idx in list(remaining)[:min(100, len(remaining))]:  # Limit evaluations
            new_set = selected | {idx}
            new_hv = compute_hv(new_set)
            contrib = new_hv - current_hv
            if contrib > best_contrib:
                best_contrib = contrib
                best_idx = idx

        if best_idx is None:
            best_idx = random.choice(list(remaining))

        selected.add(best_idx)
        remaining.remove(best_idx)

    # 2. Evolutionary population with size-aware mutation
    population = [set(selected) for _ in range(8)]
    for i in range(1, 8):
        # Create diverse initial solutions
        if i % 2 == 0:
            population[i] = set(random.sample(range(n), k))
        else:
            # Perturb greedy solution
            pop = set(selected)
            for _ in range(random.randint(1, 3)):
                if pop and random.random() < 0.5:
                    pop.remove(random.choice(list(pop)))
                if len(pop) < k and (n - len(pop)) > 0:
                    pop.add(random.choice(list(set(range(n)) - pop)))
            while len(pop) < k:
                pop.add(random.choice(list(set(range(n)) - pop)))
            while len(pop) > k:
                pop.remove(random.choice(list(pop)))
            population[i] = pop

    fitness = [compute_hv(ind) for ind in population]

    for _ in range(30):  # Reduced generations
        # Tournament selection
        parent_idx = random.sample(range(len(population)), 3)
        parent_idx = max(parent_idx, key=lambda i: fitness[i])
        child = set(population[parent_idx])

        # Size-aware mutation
        size_diff = len(child) - k
        if size_diff < 0:
            # Add bias
            if random.random() < 0.8 and (n - len(child)) > 0:
                child.add(random.choice(list(set(range(n)) - child)))
            elif len(child) > 1:
                child.remove(random.choice(list(child)))
        elif size_diff > 0:
            # Remove bias
            if random.random() < 0.8 and len(child) > 1:
                child.remove(random.choice(list(child)))
            elif (n - len(child)) > 0:
                child.add(random.choice(list(set(range(n)) - child)))
        else:
            # Balanced mutation
            if random.random() < 0.5 and (n - len(child)) > 0:
                child.add(random.choice(list(set(range(n)) - child)))
            elif len(child) > 1:
                child.remove(random.choice(list(child)))

        # Ensure correct size
        while len(child) > k:
            child.remove(random.choice(list(child)))
        while len(child) < k:
            child.add(random.choice(list(set(range(n)) - child)))

        # Environmental selection
        child_hv = compute_hv(child)
        if child_hv > min(fitness):
            min_idx = np.argmin(fitness)
            population[min_idx] = child
            fitness[min_idx] = child_hv

    # 3. Elite local refinement only on best solution
    best_idx = np.argmax(fitness)
    best_set = population[best_idx]
    best_hv = fitness[best_idx]

    improved = True
    while improved:
        improved = False

        # Compute contributions once
        contributions = {}
        for idx in best_set:
            temp_set = best_set - {idx}
            contributions[idx] = best_hv - compute_hv(temp_set)

        # Find worst point
        worst = min(contributions, key=contributions.get)

        # Try swaps with limited candidates
        candidates = list(set(range(n)) - best_set)
        random.shuffle(candidates)
        for cand in candidates[:min(50, len(candidates))]:  # Limit swap checks
            new_set = (best_set - {worst}) | {cand}
            new_hv = compute_hv(new_set)
            if new_hv > best_hv + 1e-10:
                best_set = new_set
                best_hv = new_hv
                improved = True
                break

    return points[list(best_set)]

def HSS(points, k: int, reference_point) -> np.ndarray:
    if reference_point is None:
        reference_point = np.max(points, axis=0) * 1.1

    n, d = points.shape

    # 缓存超体积计算
    hv_cache = {}

    def compute_hv(indices):
        key = tuple(sorted(indices))
        if key not in hv_cache:
            if not indices:
                hv_cache[key] = 0.0
            else:
                hv = pg.hypervolume(points[list(indices)])
                hv_cache[key] = hv.compute(reference_point)
        return hv_cache[key]

    # 1. 基于贡献的贪心初始化
    def greedy_by_contributions():
        selected = set()
        contributions = {}

        # 初始贡献：单个点的超体积
        for i in range(n):
            contributions[i] = compute_hv([i])

        while len(selected) < k:
            # 选择贡献最大的点
            best_idx = max((idx for idx in range(n) if idx not in selected), 
                          key=lambda x: contributions[x], default=None)

            if best_idx is None:
                # 如果没有候选点，随机选择一个
                remaining = [i for i in range(n) if i not in selected]
                if remaining:
                    best_idx = random.choice(remaining)
                else:
                    break

            selected.add(best_idx)

            # 更新剩余点的贡献估计
            if len(selected) < k:
                for i in range(n):
                    if i not in selected:
                        # 近似计算新贡献：与当前集合的边际贡献
                        new_set = list(selected) + [i]
                        old_hv = compute_hv(list(selected))
                        new_hv = compute_hv(new_set)
                        contributions[i] = new_hv - old_hv

        return list(selected)

    # 2. 迭代删除-添加优化
    def iterative_removal_addition(initial_set):
        current_set = set(initial_set)
        best_hv = compute_hv(list(current_set))

        improved = True
        while improved:
            improved = False

            # 删除阶段：移除贡献最小的点
            if len(current_set) > 1:
                worst_contrib = float('inf')
                worst_point = None

                for idx in current_set:
                    temp_set = current_set - {idx}
                    contrib = best_hv - compute_hv(list(temp_set))
                    if contrib < worst_contrib:
                        worst_contrib = contrib
                        worst_point = idx

                # 尝试移除贡献最小的点
                if worst_point is not None:
                    candidate_set = current_set - {worst_point}

                    # 添加阶段：寻找最佳替换点
                    best_add = None
                    best_add_hv = -float('inf')

                    for i in range(n):
                        if i not in candidate_set:
                            new_set = list(candidate_set) + [i]
                            new_hv = compute_hv(new_set)
                            if new_hv > best_add_hv:
                                best_add_hv = new_hv
                                best_add = i

                    if best_add is not None and best_add_hv > best_hv:
                        candidate_set.add(best_add)
                        current_set = candidate_set
                        best_hv = best_add_hv
                        improved = True

            # 如果没有改进，尝试随机扰动
            if not improved and len(current_set) == k:
                # 随机交换两个点
                for _ in range(min(10, n)):
                    remove_idx = random.choice(list(current_set))
                    candidate_set = current_set - {remove_idx}

                    available = [i for i in range(n) if i not in candidate_set]
                    if not available:
                        continue

                    add_idx = random.choice(available)
                    new_set = list(candidate_set) + [add_idx]
                    new_hv = compute_hv(new_set)

                    if new_hv > best_hv:
                        current_set = set(new_set)
                        best_hv = new_hv
                        improved = True
                        break

        return list(current_set)

    # 3. 邻域搜索优化
    def neighborhood_search(current_set):
        best_set = current_set.copy()
        best_hv = compute_hv(best_set)

        # 尝试所有可能的单点替换
        for i in range(len(best_set)):
            for j in range(n):
                if j in best_set:
                    continue

                new_set = best_set.copy()
                new_set[i] = j
                new_hv = compute_hv(new_set)

                if new_hv > best_hv:
                    best_set = new_set
                    best_hv = new_hv

        return best_set

    # 主算法流程
    # 步骤1: 贪心初始化
    initial_set = greedy_by_contributions()

    # 步骤2: 迭代删除-添加优化
    improved_set = iterative_removal_addition(initial_set)

    # 步骤3: 邻域搜索
    final_set = neighborhood_search(improved_set)

    # 确保返回k个点
    if len(final_set) != k:
        # 如果不足k个点，用贪心补充
        current = set(final_set)
        while len(current) < k:
            best_contrib = -float('inf')
            best_idx = None

            for i in range(n):
                if i not in current:
                    new_set = list(current) + [i]
                    contrib = compute_hv(new_set) - compute_hv(list(current))
                    if contrib > best_contrib:
                        best_contrib = contrib
                        best_idx = i

            if best_idx is not None:
                current.add(best_idx)
            else:
                break

        final_set = list(current)

    return points[final_set]
